SELECT COUNT(*) > 0
FROM recruitment_application
WHERE recruitment_id = #{recruitmentId}
  AND applicant_email = #{applicantEmail}

SELECT

FROM recruitment_application ra
LEFT JOIN recruitment r ON r.recruitment_id = ra.recruitment_id
LEFT JOIN user u ON u.email = ra.applicant_email
WHERE ra.recruitment_id = #{recruitmentId}
  AND ra.applicant_email = #{applicantEmail}

SELECT

FROM recruitment_application ra
INNER JOIN recruitment r ON r.recruitment_id = ra.recruitment_id
LEFT JOIN user u ON u.email = ra.applicant_email
WHERE ra.recruitment_id = #{recruitmentId}
  AND ra.application_id = #{applicationId}

mapper.update:
UPDATE recruitment_application
SET intro = #{intro}
WHERE application_id = #{applicationId}
  AND status = 'PENDING'
  AND viewed_at IS NULL
